LISTO YA REALIZO LOS CAMBIOS EN LA UAD Y ME PROPORCIONO ESTE CODIGO SQL PARA QUE LO INGRESARA EN LAS DOS DB Y YA LO HICE:
-- 1. Agregar columna folder_id a la tabla de procedimientos
-- Esto permite a NEXUS saber en qué 'acordeón' meter el documento sin hacer JOINs complejos.
ALTER TABLE public.procedures 
ADD COLUMN IF NOT EXISTS folder_id UUID;

-- 2. Agregar columna folder_name a la tabla de carpetas publicadas
-- Esto permite a NEXUS mostrar el nombre de la carpeta (ej. "Calidad") sin consultar la tabla protegida 'folders'.
ALTER TABLE public.published_folders 
ADD COLUMN IF NOT EXISTS folder_name TEXT;

-- 3. Asegurar permisos de lectura pública sobre las nuevas columnas
-- (Supabase suele heredarlos, pero esto fuerza la actualización de caché de esquema)
GRANT SELECT ON public.procedures TO anon;
GRANT SELECT ON public.published_folders TO anon;
